SELECT category_id, COUNT(*) AS hieroglyph_count
FROM hieroglyphs
GROUP BY category_id;

SELECT symbol
FROM hieroglyphs
WHERE symbol_type = 'logogram';

SELECT DISTINCT h.name
FROM hieroglyphs h
WHERE h.last_updated >= DATE('now', '-1 month');

SELECT name
FROM hieroglyphs
ORDER BY name ASC;

SELECT DISTINCT username
FROM users
WHERE user_id IN (
  SELECT DISTINCT user_id
  FROM user_hieroglyphs
);

SELECT name, phonetic_value, last_updated
FROM hieroglyphs
ORDER BY last_updated DESC;

SELECT contribution_date, contribution_type
FROM user_hieroglyphs
ORDER BY contribution_date DESC;

SELECT name, phonetic_value
FROM hieroglyphs
ORDER BY phonetic_value ASC;
